const MAX_LEN = 4000;
const sanitizedItems = items.map((item) => {
  const rawMessage = item.json.chatInput ?? item.json.message ?? '';
  let cleanMessage = String(rawMessage).trim().replace(/\s+/g, ' ');
  if (cleanMessage.length > MAX_LEN) cleanMessage = cleanMessage.slice(0, MAX_LEN);
  const sessionId = item.json.sessionId ?? $execution.id;
  console.log(`[${new Date().toISOString()}] session=${sessionId} len=${cleanMessage.length}`);
  return { json: { ...item.json, chatInput: cleanMessage, originalMessage: rawMessage, sessionId, isEmpty: cleanMessage.length === 0 } };
});
return sanitizedItems;

const count = items.length;
const itemsToReturn = [];
const keyMap = { workshop_owner_name:'Owner Name',workshop_phone:'Phone',workshop_name:'Workshop Name',workshop_id:'Workshop ID',workshop_code:'Code',workshop_status:'Status',city:'City',district:'District',province:'Province',license_status:'License Status',valid_until:'Valid Until',payment_status:'Payment Status',fee_amount:'Fee Amount',full_name:'Full Name',cnic_number:'CNIC',phone_primary:'Phone',profile_status:'Profile Status',test_result:'Test Result',certificate_no:'Certificate No',test_date:'Test Date',inspection_result:'Inspection Result',total_score:'Total Score',inspection_date:'Inspection Date',created_at:'Created At',workshop_email:'Email' };
function titleCase(key) { return key.replace(/_/g,' ').replace(/\b\w/g,(c)=>c.toUpperCase()); }
function extractJson(raw) { if(raw===null||raw===undefined)return[]; if(Array.isArray(raw)||typeof raw==='object')return raw; let s=String(raw).trim(); s=s.replace(/^\s*```(?:json|javascript|js)?\s*/i,''); s=s.replace(/\s*```\s*$/i,''); s=s.trim(); const candidates=['[','{'].map((c)=>s.indexOf(c)).filter((i)=>i!==-1); if(candidates.length){const start=Math.min(...candidates); if(start>0)s=s.slice(start);} const lastBracket=Math.max(s.lastIndexOf(']'),s.lastIndexOf('}')); if(lastBracket!==-1&&lastBracket<s.length-1)s=s.slice(0,lastBracket+1); return JSON.parse(s); }
for(const item of items){const rawOutput=item.json.output??item.json.choices?.[0]?.message?.content??[];let dataArray;try{dataArray=extractJson(rawOutput);}catch(e){const preview=String(rawOutput).substring(0,300);throw new Error(`Export failed: agent did not return parseable JSON. ${e.message}. Raw: ${preview}`);} if(!Array.isArray(dataArray))dataArray=[dataArray]; for(const record of dataArray){if(record===null||typeof record!=='object')continue;const newRecord={};for(const key of Object.keys(record)){const cleanKey=keyMap[key]??titleCase(key);newRecord[cleanKey]=record[key];}itemsToReturn.push({json:newRecord});}}
if(itemsToReturn.length===0)throw new Error('Export produced zero usable records — nothing to append.');
return itemsToReturn;

function extractJson(raw){if(!raw)throw new Error('No output from PDF agent');let s=String(raw).trim().replace(/^```(?:json)?\s*/i,'').replace(/```\s*$/,'').trim();const si=s.indexOf('{');if(si>0)s=s.slice(si);const ei=s.lastIndexOf('}');if(ei!==-1&&ei<s.length-1)s=s.slice(0,ei+1);return JSON.parse(s);}
const raw=items[0].json.output??'';
let report;
try{report=extractJson(raw);}catch(e){throw new Error('PDF agent did not return valid JSON: '+e.message);}
const ts=report.generated_at?new Date(report.generated_at).toLocaleString():new Date().toLocaleString();
let sectionsHtml='';
for(const sec of(report.sections||[])){if(!sec.rows||sec.rows.length===0)continue;const headers=Object.keys(sec.rows[0]);const thead=headers.map(h=>`<th>${h}</th>`).join('');const tbody=sec.rows.map(r=>'<tr>'+headers.map(h=>`<td>${r[h]??''}</td>`).join('')+'</tr>').join('');sectionsHtml+=`<div class="section"><h2>${sec.heading||'Data'}</h2><table><thead><tr>${thead}</tr></thead><tbody>${tbody}</tbody></table></div>`;}
const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;margin:32px;color:#1a1a2e}h1{color:#1a1a2e;border-bottom:3px solid #16213e;padding-bottom:8px}h2{color:#16213e;margin-top:28px}.meta{color:#666;font-size:13px;margin-bottom:20px}.summary{background:#f0f4ff;border-left:4px solid #4361ee;padding:12px 16px;margin:16px 0;border-radius:4px}table{width:100%;border-collapse:collapse;margin-top:10px;font-size:13px}th{background:#1a1a2e;color:#fff;padding:8px 10px;text-align:left}td{padding:7px 10px;border-bottom:1px solid #e0e0e0}tr:nth-child(even) td{background:#f7f9ff}.section{margin-bottom:32px}.footer{margin-top:40px;font-size:11px;color:#999;text-align:center}</style></head><body><h1>📊 ${report.report_title||'LAWMIS Report'}</h1><p class="meta">Generated: ${ts} &nbsp;|&nbsp; LAWMIS Workshop Information System</p>${report.summary?`<div class="summary"><strong>Executive Summary:</strong> ${report.summary}</div>`:''} ${sectionsHtml}<div class="footer">LAWMIS — Confidential &nbsp;|&nbsp; ${ts}</div></body></html>`;
return [{json:{htmlContent:html,reportTitle:report.report_title||'LAWMIS Report',rowCount:(report.sections||[]).reduce((a,s)=>a+(s.rows||[]).length,0)}}];

function extractJson(raw){if(!raw)throw new Error('No output from PPTX agent');let s=String(raw).trim().replace(/^```(?:json)?\s*/i,'').replace(/```\s*$/,'').trim();const si=s.indexOf('{');if(si>0)s=s.slice(si);const ei=s.lastIndexOf('}');if(ei!==-1&&ei<s.length-1)s=s.slice(0,ei+1);return JSON.parse(s);}
const raw=items[0].json.output??'';
let pres;
try{pres=extractJson(raw);}catch(e){throw new Error('PPTX agent did not return valid JSON: '+e.message);}
const ts=pres.generated_at?new Date(pres.generated_at).toLocaleString():new Date().toLocaleString();
const slides=pres.slides||[];
let slidesHtml='';
for(const[i,slide]of slides.entries()){const c=slide.content||{};let body='';
if(slide.slide_type==='title'){body=`<div class="title-slide"><h1>${slide.slide_title}</h1><p class="subtitle">${c.subtitle||''}</p><p class="ts">${ts}</p></div>`;}
else if(slide.slide_type==='kpi_grid'){const kpis=(c.kpis||[]).map(k=>`<div class="kpi-box"><div class="kpi-val">${k.value}</div><div class="kpi-lbl">${k.label}</div></div>`).join('');body=`<h2>${slide.slide_title}</h2><div class="kpi-grid">${kpis}</div>`;}
else if(slide.slide_type==='table'){const headers=(c.headers||[]).map(h=>`<th>${h}</th>`).join('');const rows=(c.rows||[]).map(r=>'<tr>'+(r||[]).map(v=>`<td>${v??''}</td>`).join('')+'</tr>').join('');body=`<h2>${slide.slide_title}</h2><table><thead><tr>${headers}</tr></thead><tbody>${rows}</tbody></table>`;}
else if(slide.slide_type==='chart_data'){const labels=c.chart_labels||[];const vals=c.chart_values||[];const max=Math.max(...vals,1);const bars=labels.map((l,i)=>`<div class="bar-row"><div class="bar-lbl">${l}</div><div class="bar" style="width:${Math.round((vals[i]||0)/max*100)}%">${vals[i]||0}</div></div>`).join('');body=`<h2>${slide.slide_title}</h2><div class="chart">${bars}</div>`;}
else{body=`<h2>${slide.slide_title}</h2><p class="summary-text">${c.text||''}</p>`;}
slidesHtml+=`<div class="slide"><div class="slide-num">Slide ${i+1}</div>${body}</div>`;}
const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:Arial,sans-serif;background:#f0f0f0;margin:0;padding:24px}.slide{background:#fff;width:720px;min-height:405px;margin:0 auto 32px;border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,.15);padding:36px 48px;box-sizing:border-box;position:relative;page-break-after:always}.slide-num{position:absolute;top:12px;right:20px;font-size:11px;color:#aaa}.title-slide{text-align:center;padding-top:60px}.title-slide h1{font-size:32px;color:#1a1a2e}.subtitle{font-size:18px;color:#555}.ts{font-size:12px;color:#aaa;margin-top:16px}h2{color:#1a1a2e;font-size:20px;border-bottom:2px solid #4361ee;padding-bottom:6px}.kpi-grid{display:flex;flex-wrap:wrap;gap:16px;margin-top:16px}.kpi-box{background:#f0f4ff;border-radius:8px;padding:16px 24px;text-align:center;flex:1;min-width:120px}.kpi-val{font-size:28px;font-weight:700;color:#4361ee}.kpi-lbl{font-size:12px;color:#555;margin-top:4px}table{width:100%;border-collapse:collapse;font-size:13px}th{background:#1a1a2e;color:#fff;padding:8px 10px;text-align:left}td{padding:7px 10px;border-bottom:1px solid #e8e8e8}tr:nth-child(even) td{background:#f7f9ff}.bar-row{display:flex;align-items:center;margin-bottom:8px}.bar-lbl{width:120px;font-size:12px;color:#444;flex-shrink:0}.bar{background:linear-gradient(90deg,#4361ee,#7c83fd);height:24px;border-radius:4px;display:flex;align-items:center;padding:0 8px;color:#fff;font-size:12px;font-weight:700;min-width:32px}.summary-text{font-size:15px;color:#333;line-height:1.7;background:#f7f9ff;padding:20px;border-radius:8px}</style></head><body><h1 style="text-align:center;color:#1a1a2e;margin-bottom:24px">${pres.presentation_title||'LAWMIS Presentation'}</h1>${slidesHtml}</body></html>`;
return [{json:{htmlContent:html,presentationTitle:pres.presentation_title||'LAWMIS Presentation',slideCount:slides.length},binary:{data:{data:Buffer.from(html).toString('base64'),mimeType:'text/html',fileName:'presentation.html'}}}];
